@using sv_4c697f33c81043a5aba1a201fe9ebef3.Models
@using sv_4c697f33c81043a5aba1a201fe9ebef3.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        @* ── Left Sidebar ── *@
        <aside class="col-lg-3 mb-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Filters</h5>

                    @* Category checkboxes *@
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Category</label>
                        @if (_categories is null)
                        {
                            <p class="text-muted small">Loading categories…</p>
                        }
                        else
                        {
                            @foreach (var cat in _categories)
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                           checked="@_selectedCategories.Contains(cat)"
                                           @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                                    <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                                </div>
                            }
                        }
                    </div>

                    @* Price range *@
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Price Range</label>
                        <div class="row g-2">
                            <div class="col-6">
                                <input type="number" class="form-control form-control-sm" placeholder="Min"
                                       @bind="_minPrice" min="0" step="0.01" />
                            </div>
                            <div class="col-6">
                                <input type="number" class="form-control form-control-sm" placeholder="Max"
                                       @bind="_maxPrice" min="0" step="0.01" />
                            </div>
                        </div>
                    </div>

                    @* In-stock toggle *@
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync" disabled="@_loading">
                            Apply Filters
                        </button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync" disabled="@_loading">
                            Clear Filters
                        </button>
                    </div>
                </div>
            </div>
        </aside>

        @* ── Main Content ── *@
        <section class="col-lg-9">
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                <div>
                    <label class="form-label mb-0 me-2 fw-semibold" for="sortBy">Sort by</label>
                    <select id="sortBy" class="form-select form-select-sm d-inline-block w-auto"
                            @bind="_sortBy" @bind:after="OnSortChangedAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    @if (_result is not null && _result.Items.Count > 0)
                    {
                        var first = (_result.Page - 1) * _result.PageSize + 1;
                        var last = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
                        @($"Showing {first}–{last} of {_result.TotalCount} products")
                    }
                </span>
            </div>

            @* Loading state *@
            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products…</p>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                @* Empty state *@
                <div class="text-center py-5">
                    <h5 class="text-muted">No products found</h5>
                    <p class="text-muted">Try adjusting your filters or clearing them.</p>
                </div>
            }
            else
            {
                @* Product grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-md-3 g-4">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="OnProductSelected"
                                         OnAddToCart="OnAddToCart" />
                        </div>
                    }
                </div>

                @* Pagination *@
                @{
                    var totalPages = (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);
                }
                @if (totalPages > 1)
                {
                    <nav aria-label="Product pagination" class="mt-4">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                        disabled="@(_currentPage == 1)">
                                    Previous
                                </button>
                            </li>

                            @for (var p = 1; p <= totalPages; p++)
                            {
                                var pageNum = p;
                                <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">
                                        @pageNum
                                    </button>
                                </li>
                            }

                            <li class="page-item @(_currentPage == totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                        disabled="@(_currentPage == totalPages)">
                                    Next
                                </button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </section>
    </div>
}

