@using sv_4c697f33c81043a5aba1a201fe9ebef3.Models

<div class="card h-100 product-card" role="button" @onclick="HandleCardClick">
    @* Placeholder image *@
    <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
         style="height:180px;" role="img" aria-label="@Product.Name">
        <span class="text-muted small text-center px-2">@Product.Name</span>
    </div>

    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1" aria-label="@($"Rating: {RoundedRating} out of 5")">@RatingStars</p>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }

        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int RoundedRating => (int)Math.Round(Product.Rating, MidpointRounding.AwayFromZero);

    private string RatingStars
    {
        get
        {
            var filled = Math.Clamp(RoundedRating, 0, 5);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task HandleCardClick()
    {
        if (OnProductSelected.HasDelegate)
            await OnProductSelected.InvokeAsync(Product);
